// src/views/user/MyProfile/composables/useModules.js
import { ref, computed } from 'vue'
import { moduleConfig } from '../constants/moduleConfig'
import { BriefcaseIcon } from '@heroicons/vue/24/outline'
import { cityOptions } from '../constants/cityOptions'

export function useModules() {
  const activeModules = ref([])
  const currentModule = ref(null)
  const currentItem = ref(null)

  const inactiveModules = computed(() => {
    const activeIds = activeModules.value.map(m => m.id)
    return moduleConfig.filter(m => !activeIds.includes(m.id))
  })

  const editModule = (moduleId, item = null) => {
    currentModule.value = activeModules.value.find(m => m.id === moduleId)
    currentItem.value = item
  }

  const addItem = (moduleId) => {
    currentModule.value = activeModules.value.find(m => m.id === moduleId)
    currentItem.value = null
  }

  const removeModule = (moduleId) => {
    const index = activeModules.value.findIndex(m => m.id === moduleId)
    if (index > -1) {
      activeModules.value.splice(index, 1)
    }
  }

  const activateModule = (moduleId) => {
    const module = moduleConfig.find(m => m.id === moduleId)
    if (module) {
      activeModules.value.push({
        ...module,
        items: []
      })
    }
  }

  const moduleTypes = {
    job_intention: {
      id: 'job_intention',
      type: 'job_intention',
      name: '求职意向',
      icon: BriefcaseIcon,
      required: false,
      multiple: false,
      formConfig: {
        fields: [
          {
            name: 'position',
            label: '期望职位',
            type: 'input',
            required: true,
            placeholder: '请输入期望职位'
          },
          {
            name: 'city',
            label: '期望城市',
            type: 'cascader',
            required: true,
            placeholder: '请选择期望城市',
            options: cityOptions
          },
          {
            name: 'salary',
            label: '期望薪资',
            type: 'salary-range',
            placeholder: ['最低薪资', '最高薪资']
          },
          {
            name: 'availability',
            label: '到岗时间',
            type: 'select',
            required: true,
            options: [
              { label: '随时到岗', value: 'immediately' },
              { label: '一周内', value: 'one_week' },
              { label: '一个月内', value: 'one_month' },
              { label: '三个月内', value: 'three_months' },
              { label: '待商议', value: 'negotiable' }
            ]
          },
          {
            name: 'job_type',
            label: '工作类型',
            type: 'select',
            required: true,
            options: [
              { label: '全职', value: 'full_time' },
              { label: '兼职', value: 'part_time' },
              { label: '实习', value: 'internship' },
              { label: '自由职业', value: 'freelance' }
            ]
          }
        ]
      }
    },
    // ... 其他模块类型
  }

  return {
    activeModules,
    inactiveModules,
    currentModule,
    currentItem,
    editModule,
    addItem,
    removeModule,
    activateModule
  }
}
